import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSSafeServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Your input:</h1>");

        // Encode user input to prevent XSS
        Encoder encoder = ESAPI.encoder();
        String encodedInput = encoder.encodeForHTML(userInput);

        out.println("<p>" + encodedInput + "</p>"); // Safe line
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
